package server

import (
	"crypto/rand"
	"database/sql"
	"encoding/hex"
	"errors"
	"net/http"
	"strings"
	"time"
)

type User struct {
	ID        int
	Username  string
	AvatarURL string
	Bio       string
}

func (u *User) Initial() string {
	if len(u.Username) == 0 {
		return "?"
	}
	return strings.ToUpper(string([]rune(u.Username)[0]))
}

func GetSessionUser(r *http.Request, dbConn *sql.DB) (*User, error) {
	cookie, err := r.Cookie("session_id")
	if err != nil {
		return nil, errors.New("no session")
	}

	sessionID := cookie.Value

	var userID int
	var expiresAt time.Time

	err = dbConn.QueryRow(`
		SELECT user_id, expires_at
		FROM sessions
		WHERE id = $1
	`, sessionID).Scan(&userID, &expiresAt)

	if err != nil {
		return nil, errors.New("invalid session")
	}

	if time.Now().After(expiresAt) {
		_, _ = dbConn.Exec(`DELETE FROM sessions WHERE id = $1`, sessionID)
		return nil, errors.New("session expired")
	}

	var username string
	var avatarURL string
	var bio string

	err = dbConn.QueryRow(`
		SELECT username, COALESCE(avatar_url, ''), COALESCE(bio, '')
		FROM users
		WHERE id = $1
	`, userID).Scan(&username, &avatarURL, &bio)

	if err != nil {
		return nil, err
	}

	return &User{
		ID:        userID,
		Username:  username,
		AvatarURL: avatarURL,
		Bio:       bio,
	}, nil
}

func CreateSession(userID int, dbConn *sql.DB) (string, error) {
	sessionIDBytes := make([]byte, 32)
	_, err := rand.Read(sessionIDBytes)
	if err != nil {
		return "", err
	}

	sessionID := hex.EncodeToString(sessionIDBytes)
	expiresAt := time.Now().Add(24 * time.Hour)

	_, err = dbConn.Exec(`
		INSERT INTO sessions (id, user_id, expires_at)
		VALUES ($1, $2, $3)
	`, sessionID, userID, expiresAt)

	return sessionID, err
}

func DestroySession(sessionID string, dbConn *sql.DB) error {
	_, err := dbConn.Exec(`DELETE FROM sessions WHERE id = $1`, sessionID)
	return err
}

package server

import (
	"database/sql"
	"time"
)

type Message struct {
	ID         int       `json:"id"`
	CategoryID int       `json:"category_id"`
	UserID     int       `json:"user_id"`
	Username   string    `json:"username"`
	AvatarURL  string    `json:"avatar_url"`
	Content    string    `json:"content"`
	CreatedAt  time.Time `json:"created_at"`
}

type Category struct {
	ID          int    `json:"id"`
	Name        string `json:"name"`
	Description string `json:"description"`
}

func GetCategories(dbConn *sql.DB) ([]Category, error) {
	rows, err := dbConn.Query(`
		SELECT id, name, description
		FROM categories
		ORDER BY name
	`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var categories []Category

	for rows.Next() {
		var c Category
		if err := rows.Scan(&c.ID, &c.Name, &c.Description); err != nil {
			return nil, err
		}
		categories = append(categories, c)
	}

	return categories, rows.Err()
}

func GetCategoryByName(name string, dbConn *sql.DB) (*Category, error) {
	var c Category

	err := dbConn.QueryRow(`
		SELECT id, name, description
		FROM categories
		WHERE LOWER(TRIM(name)) = LOWER(TRIM($1))
		LIMIT 1
	`, name).Scan(&c.ID, &c.Name, &c.Description)

	if err == nil {
		return &c, nil
	}

	if err != sql.ErrNoRows {
		return nil, err
	}

	err = dbConn.QueryRow(`
		INSERT INTO categories (name, description)
		VALUES ($1, $2)
		ON CONFLICT (name) DO UPDATE SET name = EXCLUDED.name
		RETURNING id, name, description
	`, name, "Catégorie "+name).Scan(&c.ID, &c.Name, &c.Description)

	if err != nil {
		return nil, err
	}

	return &c, nil
}

package server

import (
	"html"
	"net/http"
	"strings"
)

func registerHandler(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodGet:
		renderRegisterForm(w, "")
	case http.MethodPost:
		username := strings.TrimSpace(r.FormValue("username"))
		password := r.FormValue("password")

		if username == "" || password == "" {
			renderRegisterForm(w, "Veuillez remplir tous les champs.")
			return
		}

		userID, err := createUser(username, password)
		if err != nil {
			if strings.Contains(strings.ToLower(err.Error()), "duplicate") {
				renderRegisterForm(w, "Ce nom d'utilisateur existe déjà.")
				return
			}
			http.Error(w, "Erreur serveur : "+html.EscapeString(err.Error()), http.StatusInternalServerError)
			return
		}

		sessionID, err := CreateSession(userID, dbConn)
		if err != nil {
			http.Error(w, "Erreur serveur", http.StatusInternalServerError)
			return
		}

		http.SetCookie(w, &http.Cookie{
			Name:     "session_id",
			Value:    sessionID,
			Path:     "/",
			MaxAge:   86400,
			HttpOnly: true,
			SameSite: http.SameSiteLaxMode,
		})

		http.Redirect(w, r, "/", http.StatusSeeOther)
	}
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodGet:
		renderLoginForm(w, "")
	case http.MethodPost:
		username := strings.TrimSpace(r.FormValue("username"))
		password := r.FormValue("password")

		if username == "" || password == "" {
			renderLoginForm(w, "Veuillez remplir tous les champs.")
			return
		}

		userID, ok, err := authenticateUser(username, password)
		if err != nil {
			http.Error(w, "Erreur serveur : "+html.EscapeString(err.Error()), http.StatusInternalServerError)
			return
		}
		if !ok {
			renderLoginForm(w, "Identifiants incorrects.")
			return
		}

		sessionID, err := CreateSession(userID, dbConn)
		if err != nil {
			http.Error(w, "Erreur serveur", http.StatusInternalServerError)
			return
		}

		http.SetCookie(w, &http.Cookie{
			Name:     "session_id",
			Value:    sessionID,
			Path:     "/",
			MaxAge:   86400,
			HttpOnly: true,
			SameSite: http.SameSiteLaxMode,
		})

		http.Redirect(w, r, "/", http.StatusSeeOther)
	}
}

func logoutHandler(w http.ResponseWriter, r *http.Request) {
	cookie, err := r.Cookie("session_id")
	if err == nil {
		DestroySession(cookie.Value, dbConn)
	}

	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    "",
		Path:     "/",
		MaxAge:   -1,
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
	})

	http.Redirect(w, r, "/", http.StatusSeeOther)
}

func renderRegisterForm(w http.ResponseWriter, message string) {
	data := struct {
		Message string
	}{
		Message: message,
	}
	_ = authTemplates.ExecuteTemplate(w, "register.html", data)
}

func renderLoginForm(w http.ResponseWriter, message string) {
	data := struct {
		Message string
	}{
		Message: message,
	}
	_ = authTemplates.ExecuteTemplate(w, "login.html", data)
}

package server

import (
	"database/sql"

	"golang.org/x/crypto/bcrypt"
)

func createUser(username, password string) (int, error) {
	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return 0, err
	}

	var id int

	err = dbConn.QueryRow(`
		INSERT INTO users (username, password_hash)
		VALUES ($1, $2)
		RETURNING id
	`, username, string(hash)).Scan(&id)

	return id, err
}

func authenticateUser(username, password string) (int, bool, error) {
	var userID int
	var hash string

	err := dbConn.QueryRow(`
		SELECT id, password_hash
		FROM users
		WHERE username = $1
	`, username).Scan(&userID, &hash)

	if err != nil {
		if err == sql.ErrNoRows {
			return 0, false, nil
		}
		return 0, false, err
	}

	if err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password)); err != nil {
		return 0, false, nil
	}

	return userID, true, nil
}

