package server

import (
	"encoding/json"
	"net/http"
	"strings"
)

type APIResponse struct {
	Success bool        `json:"success"`
	Message string      `json:"message,omitempty"`
	Data    interface{} `json:"data,omitempty"`
}

type MessageBody struct {
	Category string `json:"category"`
	Content  string `json:"content"`
}

func messagesAPIHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	switch r.Method {
	case http.MethodGet:
		handleGetMessages(w, r)
	case http.MethodPost:
		handlePostMessage(w, r)
	default:
		json.NewEncoder(w).Encode(APIResponse{
			Success: false,
			Message: "method not allowed",
		})
	}
}

func handleGetMessages(w http.ResponseWriter, r *http.Request) {
	categoryName := strings.TrimSpace(r.URL.Query().Get("category"))

	if categoryName == "" {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "category manquant",
		})
		return
	}

	cat, err := GetCategoryByName(categoryName, dbConn)
	if err != nil {
		writeJSON(w, http.StatusNotFound, APIResponse{
			Success: false,
			Message: "catégorie introuvable",
		})
		return
	}

	messages, err := GetMessages(cat.ID, dbConn)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{
			Success: false,
			Message: "erreur messages",
		})
		return
	}

	userID := 0
	if u, err := GetSessionUser(r, dbConn); err == nil {
		userID = u.ID
	}

	type msgWithReactions struct {
		Message
		Reactions []ReactionGroup `json:"reactions"`
	}

	var result []msgWithReactions
	for _, m := range messages {
		groups, _ := GetReactions(m.ID, userID)
		if groups == nil {
			groups = []ReactionGroup{}
		}
		result = append(result, msgWithReactions{
			Message:   m,
			Reactions: groups,
		})
	}

	if result == nil {
		result = []msgWithReactions{}
	}

	writeJSON(w, http.StatusOK, APIResponse{
		Success: true,
		Data:    result,
	})
}

func handlePostMessage(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		writeJSON(w, http.StatusUnauthorized, APIResponse{
			Success: false,
			Message: "Non authentifié",
		})
		return
	}

	var body MessageBody

	err = json.NewDecoder(r.Body).Decode(&body)
	if err != nil {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "json invalide",
		})
		return
	}

	categoryName := strings.TrimSpace(body.Category)
	content := strings.TrimSpace(body.Content)

	if categoryName == "" || content == "" {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "paramètres manquants",
		})
		return
	}

	cat, err := GetCategoryByName(categoryName, dbConn)
	if err != nil {
		writeJSON(w, http.StatusNotFound, APIResponse{
			Success: false,
			Message: "catégorie introuvable",
		})
		return
	}

	msg, err := PostMessage(cat.ID, user.ID, content, dbConn)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{
			Success: false,
			Message: "erreur message",
		})
		return
	}

	writeJSON(w, http.StatusCreated, APIResponse{
		Success: true,
		Data:    msg,
	})
}

func writeJSON(w http.ResponseWriter, status int, data APIResponse) {
	w.Header().Set("Content-Type", "application/json; charset=utf-8")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(data)
}

package server

type Reaction struct {
	ID        int    `json:"id"`
	MessageID int    `json:"message_id"`
	UserID    int    `json:"user_id"`
	Emoji     string `json:"emoji"`
	Username  string `json:"username"`
}

type ReactionGroup struct {
	Emoji  string   `json:"emoji"`
	Count  int      `json:"count"`
	UserID int      `json:"user_id"`
	Users  []string `json:"users"`
}

func GetReactions(messageID int, currentUserID int) ([]ReactionGroup, error) {
	rows, err := dbConn.Query(`
		SELECT emoji, COUNT(*) as cnt,
		       ARRAY_AGG(username) as usernames,
		       BOOL_OR(user_id = $2) as is_mine
		FROM reactions r
		JOIN users u ON u.id = r.user_id
		WHERE r.message_id = $1
		GROUP BY emoji
		ORDER BY cnt DESC
	`, messageID, currentUserID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var groups []ReactionGroup

	for rows.Next() {
		var g ReactionGroup
		var usernames []string
		var isMine bool

		if err := rows.Scan(&g.Emoji, &g.Count, &usernames, &isMine); err != nil {
			return nil, err
		}

		g.Users = usernames
		if isMine {
			g.UserID = currentUserID
		}

		groups = append(groups, g)
	}

	return groups, rows.Err()
}

func AddReaction(messageID int, userID int, emoji string) error {
	_, err := dbConn.Exec(`
		INSERT INTO reactions (message_id, user_id, emoji)
		VALUES ($1, $2, $3)
		ON CONFLICT (message_id, user_id, emoji) DO NOTHING
	`, messageID, userID, emoji)
	return err
}

func RemoveReaction(messageID int, userID int, emoji string) error {
	_, err := dbConn.Exec(`
		DELETE FROM reactions
		WHERE message_id = $1 AND user_id = $2 AND emoji = $3
	`, messageID, userID, emoji)
	return err
}

package server

import (
	"encoding/json"
	"net/http"
	"strconv"
	"strings"
)

type ReactionBody struct {
	MessageID int    `json:"message_id"`
	Emoji     string `json:"emoji"`
}

func reactionsAPIHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		writeJSON(w, http.StatusUnauthorized, APIResponse{
			Success: false,
			Message: "Non authentifié",
		})
		return
	}

	switch r.Method {
	case http.MethodPost:
		handleAddReaction(w, r, user)
	case http.MethodDelete:
		handleRemoveReaction(w, r, user)
	default:
		json.NewEncoder(w).Encode(APIResponse{
			Success: false,
			Message: "method not allowed",
		})
	}
}

func handleAddReaction(w http.ResponseWriter, r *http.Request, user *User) {
	var body ReactionBody

	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "json invalide",
		})
		return
	}

	emoji := strings.TrimSpace(body.Emoji)
	if emoji == "" || body.MessageID == 0 {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "paramètres manquants",
		})
		return
	}

	if err := AddReaction(body.MessageID, user.ID, emoji); err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{
			Success: false,
			Message: "erreur réaction",
		})
		return
	}

	writeJSON(w, http.StatusOK, APIResponse{
		Success: true,
	})
}

func handleRemoveReaction(w http.ResponseWriter, r *http.Request, user *User) {
	messageIDStr := r.URL.Query().Get("message_id")
	emoji := strings.TrimSpace(r.URL.Query().Get("emoji"))

	messageID, err := strconv.Atoi(messageIDStr)
	if err != nil || emoji == "" {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "paramètres manquants",
		})
		return
	}

	if err := RemoveReaction(messageID, user.ID, emoji); err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{
			Success: false,
			Message: "erreur réaction",
		})
		return
	}

	writeJSON(w, http.StatusOK, APIResponse{
		Success: true,
	})
}

package server

import (
	"html/template"
	"strings"
	"time"
)

type ProfilePageData struct {
	User           *User
	JoinedAt       string
	MessageCount   int
	RecentMessages []RecentMessage
	Success        string
	Error          string
}

type RecentMessage struct {
	Content      string
	CategoryName string
	CreatedAt    time.Time
}

func buildProfileData(user *User, success, errMsg string) ProfilePageData {
	var messageCount int
	_ = dbConn.QueryRow(`SELECT COUNT(*) FROM messages WHERE user_id = $1`, user.ID).Scan(&messageCount)

	var joinedAt time.Time
	_ = dbConn.QueryRow(`SELECT created_at FROM users WHERE id = $1`, user.ID).Scan(&joinedAt)

	rows, err := dbConn.Query(`
		SELECT m.content, c.name, m.created_at
		FROM messages m
		JOIN categories c ON c.id = m.category_id
		WHERE m.user_id = $1
		ORDER BY m.created_at DESC
		LIMIT 5
	`, user.ID)
	if err != nil {
		rows = nil
	}

	var recent []RecentMessage
	if rows != nil {
		defer rows.Close()
		for rows.Next() {
			var m RecentMessage
			if rows.Scan(&m.Content, &m.CategoryName, &m.CreatedAt) == nil {
				recent = append(recent, m)
			}
		}
	}

	return ProfilePageData{
		User:           user,
		JoinedAt:       joinedAt.Format("2 January 2006"),
		MessageCount:   messageCount,
		RecentMessages: recent,
		Success:        success,
		Error:          errMsg,
	}
}

func templateFuncs() template.FuncMap {
	return template.FuncMap{
		"uppercase": strings.ToUpper,
	}
}

package server

import (
	"log"
	"net/http"
	"os"
	"strings"

	"golang.org/x/crypto/bcrypt"
)

func profileHandler(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		http.Redirect(w, r, "/login", http.StatusSeeOther)
		return
	}

	if r.Method == http.MethodPost {
		updateProfile(w, r, user)
		return
	}

	data := buildProfileData(user, "", "")
	_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
}

func updateProfile(w http.ResponseWriter, r *http.Request, user *User) {
	username := strings.TrimSpace(r.FormValue("username"))
	bio := strings.TrimSpace(r.FormValue("bio"))

	if username == "" {
		data := buildProfileData(user, "", "Le nom d'utilisateur ne peut pas être vide.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	if username != user.Username {
		var exists int
		_ = dbConn.QueryRow(`SELECT COUNT(*) FROM users WHERE username = $1 AND id != $2`, username, user.ID).Scan(&exists)
		if exists > 0 {
			data := buildProfileData(user, "", "Ce nom d'utilisateur est déjà pris.")
			_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
			return
		}
	}

	_, err := dbConn.Exec(`UPDATE users SET username = $1, bio = $2 WHERE id = $3`, username, bio, user.ID)
	if err != nil {
		data := buildProfileData(user, "", "Erreur lors de la mise à jour.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	user.Username = username
	user.Bio = bio

	data := buildProfileData(user, "Profil mis à jour.", "")
	_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
}

func profilePasswordHandler(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		http.Redirect(w, r, "/login", http.StatusSeeOther)
		return
	}

	currentPassword := r.FormValue("current_password")
	newPassword := r.FormValue("new_password")

	if currentPassword == "" || newPassword == "" {
		data := buildProfileData(user, "", "Remplis tous les champs.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	var hash string
	_ = dbConn.QueryRow(`SELECT password_hash FROM users WHERE id = $1`, user.ID).Scan(&hash)

	if err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(currentPassword)); err != nil {
		data := buildProfileData(user, "", "Mot de passe actuel incorrect.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	newHash, err := bcrypt.GenerateFromPassword([]byte(newPassword), bcrypt.DefaultCost)
	if err != nil {
		data := buildProfileData(user, "", "Erreur serveur.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	_, err = dbConn.Exec(`UPDATE users SET password_hash = $1 WHERE id = $2`, string(newHash), user.ID)
	if err != nil {
		data := buildProfileData(user, "", "Erreur serveur.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	data := buildProfileData(user, "Mot de passe changé.", "")
	_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
}

func profileDeleteHandler(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		writeJSON(w, http.StatusUnauthorized, APIResponse{Success: false, Message: "Non authentifié"})
		return
	}

	if user.AvatarURL != "" {
		os.Remove("." + user.AvatarURL)
	}

	_, err = dbConn.Exec(`DELETE FROM users WHERE id = $1`, user.ID)
	if err != nil {
		log.Printf("Delete account error: %v", err)
		writeJSON(w, http.StatusInternalServerError, APIResponse{Success: false, Message: "Erreur serveur"})
		return
	}

	cookie, _ := r.Cookie("session_id")
	if cookie != nil {
		DestroySession(cookie.Value, dbConn)
	}

	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    "",
		Path:     "/",
		MaxAge:   -1,
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
	})

	writeJSON(w, http.StatusOK, APIResponse{Success: true})
}

package server

import (
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

func profileAvatarHandler(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		writeJSON(w, http.StatusUnauthorized, APIResponse{Success: false, Message: "Non authentifié"})
		return
	}

	if err := r.ParseMultipartForm(2 << 20); err != nil {
		writeJSON(w, http.StatusBadRequest, APIResponse{Success: false, Message: "Fichier trop volumineux (max 2Mo)"})
		return
	}

	file, header, err := r.FormFile("avatar")
	if err != nil {
		writeJSON(w, http.StatusBadRequest, APIResponse{Success: false, Message: "Fichier manquant"})
		return
	}
	defer file.Close()

	contentType := header.Header.Get("Content-Type")
	if !strings.HasPrefix(contentType, "image/") {
		writeJSON(w, http.StatusBadRequest, APIResponse{Success: false, Message: "Le fichier doit être une image"})
		return
	}

	ext := filepath.Ext(header.Filename)
	if ext == "" {
		switch contentType {
		case "image/jpeg":
			ext = ".jpg"
		case "image/png":
			ext = ".png"
		case "image/gif":
			ext = ".gif"
		case "image/webp":
			ext = ".webp"
		default:
			ext = ".jpg"
		}
	}

	allowedExts := map[string]bool{".jpg": true, ".jpeg": true, ".png": true, ".gif": true, ".webp": true}
	if !allowedExts[strings.ToLower(ext)] {
		writeJSON(w, http.StatusBadRequest, APIResponse{Success: false, Message: "Format non supporté (jpg, png, gif, webp)"})
		return
	}

	if user.AvatarURL != "" {
		oldPath := "." + user.AvatarURL
		os.Remove(oldPath)
	}

	os.MkdirAll("static/avatars", 0755)

	filename := fmt.Sprintf("%d%s", user.ID, ext)
	savePath := filepath.Join("static", "avatars", filename)

	dst, err := os.Create(savePath)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{Success: false, Message: "Erreur serveur"})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, file); err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{Success: false, Message: "Erreur serveur"})
		return
	}

	avatarURL := "/static/avatars/" + filename
	_, err = dbConn.Exec(`UPDATE users SET avatar_url = $1 WHERE id = $2`, avatarURL, user.ID)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{Success: false, Message: "Erreur serveur"})
		return
	}

	writeJSON(w, http.StatusOK, APIResponse{Success: true, Data: map[string]string{"avatar_url": avatarURL}})
}

package database

import (
	"database/sql"
	"log"
	"os"

	_ "github.com/lib/pq"
)

func Connect() (*sql.DB, error) {
	dsn := os.Getenv("DATABASE_URL")

	if dsn == "" {
		log.Fatal("DATABASE_URL manquant")
	}

	log.Println("Connecting DB...")

	db, err := sql.Open("postgres", dsn)
	if err != nil {
		return nil, err
	}

	if err := db.Ping(); err != nil {
		return nil, err
	}

	log.Println("DB connected")

	return db, nil
}

package config

import "os"

type Config struct {
	Port   string
	DBUser string
	DBPass string
	DBHost string
	DBName string
}

func Load() Config {
	cfg := Config{
		Port:   getEnv("APP_PORT", ":8080"),
		DBUser: getEnv("DB_USER", ""),
		DBPass: getEnv("DB_PASS", ""),
		DBHost: getEnv("DB_HOST", ""),
		DBName: getEnv("DB_NAME", ""),
	}

	if cfg.DBHost == "" || cfg.DBUser == "" || cfg.DBName == "" {
		panic("DB configuration missing (check environment variables)")
	}

	return cfg
}

func getEnv(key, fallback string) string {
	value := os.Getenv(key)
	if value == "" {
		return fallback
	}
	return value
}

