package server

import (
	"encoding/json"
	"net/http"
	"strings"
)

type APIResponse struct {
	Success bool        `json:"success"`
	Message string      `json:"message,omitempty"`
	Data    interface{} `json:"data,omitempty"`
}

type MessageBody struct {
	Category string `json:"category"`
	Content  string `json:"content"`
}

func messagesAPIHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	switch r.Method {
	case http.MethodGet:
		handleGetMessages(w, r)
	case http.MethodPost:
		handlePostMessage(w, r)
	default:
		json.NewEncoder(w).Encode(APIResponse{
			Success: false,
			Message: "method not allowed",
		})
	}
}

func handleGetMessages(w http.ResponseWriter, r *http.Request) {
	categoryName := strings.TrimSpace(r.URL.Query().Get("category"))

	if categoryName == "" {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "category manquant",
		})
		return
	}

	cat, err := GetCategoryByName(categoryName, dbConn)
	if err != nil {
		writeJSON(w, http.StatusNotFound, APIResponse{
			Success: false,
			Message: "catégorie introuvable",
		})
		return
	}

	messages, err := GetMessages(cat.ID, dbConn)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{
			Success: false,
			Message: "erreur messages",
		})
		return
	}

	userID := 0
	if u, err := GetSessionUser(r, dbConn); err == nil {
		userID = u.ID
	}

	type msgWithReactions struct {
		Message
		Reactions []ReactionGroup `json:"reactions"`
	}

	var result []msgWithReactions
	for _, m := range messages {
		groups, _ := GetReactions(m.ID, userID)
		if groups == nil {
			groups = []ReactionGroup{}
		}
		result = append(result, msgWithReactions{
			Message:   m,
			Reactions: groups,
		})
	}

	if result == nil {
		result = []msgWithReactions{}
	}

	writeJSON(w, http.StatusOK, APIResponse{
		Success: true,
		Data:    result,
	})
}

func handlePostMessage(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		writeJSON(w, http.StatusUnauthorized, APIResponse{
			Success: false,
			Message: "Non authentifié",
		})
		return
	}

	var body MessageBody

	err = json.NewDecoder(r.Body).Decode(&body)
	if err != nil {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "json invalide",
		})
		return
	}

	categoryName := strings.TrimSpace(body.Category)
	content := strings.TrimSpace(body.Content)

	if categoryName == "" || content == "" {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "paramètres manquants",
		})
		return
	}

	cat, err := GetCategoryByName(categoryName, dbConn)
	if err != nil {
		writeJSON(w, http.StatusNotFound, APIResponse{
			Success: false,
			Message: "catégorie introuvable",
		})
		return
	}

	msg, err := PostMessage(cat.ID, user.ID, content, dbConn)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{
			Success: false,
			Message: "erreur message",
		})
		return
	}

	writeJSON(w, http.StatusCreated, APIResponse{
		Success: true,
		Data:    msg,
	})
}

func writeJSON(w http.ResponseWriter, status int, data APIResponse) {
	w.Header().Set("Content-Type", "application/json; charset=utf-8")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(data)
}

package server

type Reaction struct {
	ID        int    `json:"id"`
	MessageID int    `json:"message_id"`
	UserID    int    `json:"user_id"`
	Emoji     string `json:"emoji"`
	Username  string `json:"username"`
}

type ReactionGroup struct {
	Emoji  string   `json:"emoji"`
	Count  int      `json:"count"`
	UserID int      `json:"user_id"`
	Users  []string `json:"users"`
}

func GetReactions(messageID int, currentUserID int) ([]ReactionGroup, error) {
	rows, err := dbConn.Query(`
		SELECT emoji, COUNT(*) as cnt,
		       ARRAY_AGG(username) as usernames,
		       BOOL_OR(user_id = $2) as is_mine
		FROM reactions r
		JOIN users u ON u.id = r.user_id
		WHERE r.message_id = $1
		GROUP BY emoji
		ORDER BY cnt DESC
	`, messageID, currentUserID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var groups []ReactionGroup

	for rows.Next() {
		var g ReactionGroup
		var usernames []string
		var isMine bool

		if err := rows.Scan(&g.Emoji, &g.Count, &usernames, &isMine); err != nil {
			return nil, err
		}

		g.Users = usernames
		if isMine {
			g.UserID = currentUserID
		}

		groups = append(groups, g)
	}

	return groups, rows.Err()
}

func AddReaction(messageID int, userID int, emoji string) error {
	_, err := dbConn.Exec(`
		INSERT INTO reactions (message_id, user_id, emoji)
		VALUES ($1, $2, $3)
		ON CONFLICT (message_id, user_id, emoji) DO NOTHING
	`, messageID, userID, emoji)
	return err
}

func RemoveReaction(messageID int, userID int, emoji string) error {
	_, err := dbConn.Exec(`
		DELETE FROM reactions
		WHERE message_id = $1 AND user_id = $2 AND emoji = $3
	`, messageID, userID, emoji)
	return err
}

